  unimplementedAuthResolver,
  type McpAuthContext,
  type McpScope,
  type McpRequestLike,
  type AuthContextResolver,
} from './authContext';
// Auth (CVS-99): API-key resolver + JWT minting. OAuth "Connect" is a follow-up.
export {
  createApiKeyAuthResolver,
