1	// MCP auth crypto (CVS-99). The server mints a short-lived Supabase JWT for the
2	// authenticated user so every DB call runs under that user's RLS — the DB derives
3	// the user from the `sub` claim (requesting_user_id()) and the org from `o.id`
4	// (requesting_org_id()). Signed HS256 with the Supabase JWT secret (server-only
5	// env). Uses Web Crypto (Deno/Node/browser) — no extra dependency, and the same
6	// SHA-256 hashing convention as apiKeys.ts.
7	const enc = new TextEncoder();
8	
9	function b64urlFromBytes(bytes: Uint8Array): string {
10	  let bin = '';
11	  for (const b of bytes) bin += String.fromCharCode(b);
12	  return btoa(bin).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
13	}
14	
15	function b64urlFromString(s: string): string {
16	  return b64urlFromBytes(enc.encode(s));
17	}
18	
19	/** SHA-256 hex of an API key — matches apiKeys.ts so lookups line up. */
20	export async function hashApiKey(key: string): Promise<string> {
21	  const buf = await crypto.subtle.digest('SHA-256', enc.encode(key));
22	  return [...new Uint8Array(buf)].map((b) => b.toString(16).padStart(2, '0')).join('');
23	}
24	
25	export interface SupabaseJwtInput {
26	  /** Clerk user id → JWT `sub` → requesting_user_id(). */
27	  sub: string;
28	  /** Optional org/workspace id → JWT `o.id` → requesting_org_id(). */
29	  orgId?: string | null;
30	}
31	
32	/**
33	 * Mint a short-lived (default 5 min) Supabase-compatible JWT for a user.
34	 * @param secret the Supabase JWT secret (server-only). Throws if missing.
35	 */
36	export async function mintSupabaseJwt(
37	  input: SupabaseJwtInput,
38	  secret: string,
39	  ttlSec = 300
40	): Promise<string> {
41	  if (!secret) throw new Error('mintSupabaseJwt: missing Supabase JWT secret');
42	  const now = Math.floor(Date.now() / 1000);
43	  const header = { alg: 'HS256', typ: 'JWT' };
44	  const payload: Record<string, unknown> = {
45	    sub: input.sub,
46	    role: 'authenticated',
47	    aud: 'authenticated',
48	    iss: 'metrimap-mcp',
49	    iat: now,
50	    exp: now + ttlSec,
51	  };
52	  if (input.orgId) payload.o = { id: input.orgId };
53	
54	  const data = `${b64urlFromString(JSON.stringify(header))}.${b64urlFromString(JSON.stringify(payload))}`;
55	  const key = await crypto.subtle.importKey(
56	    'raw',
57	    enc.encode(secret),
58	    { name: 'HMAC', hash: 'SHA-256' },
59	    false,
60	    ['sign']
61	  );
62	  const sig = await crypto.subtle.sign('HMAC', key, enc.encode(data));
63	  return `${data}.${b64urlFromBytes(new Uint8Array(sig))}`;
64	}
65	
66	/** Decode (does NOT verify) a JWT's payload — for tests / debugging. */
67	export function decodeJwtPayload(token: string): Record<string, unknown> {
68	  const part = token.split('.')[1] ?? '';
69	  const b64 = part.replace(/-/g, '+').replace(/_/g, '/');
70	  return JSON.parse(atob(b64));
71	}
72

