1	// Metrimap MCP server — runnable Node transport (CVS-100 deploy).
2	//
3	// Thin adapter: it wires the shipped, tested pieces together and serves them over
4	// Streamable HTTP. All the logic lives in src/shared/lib/api/mcp (registry +
5	// dispatch + API-key auth + guards); this file only does HTTP + per-request auth.
6	//
7	// Run:   cd mcp-server && npm install && npm start   (needs the repo's root deps —
8	//        see README). Env: SUPABASE_URL, SUPABASE_ANON_KEY, SUPABASE_JWT_SECRET.
9	//
10	// NOTE: the @modelcontextprotocol/sdk transport/registerTool API evolves between
11	// versions — if `npm start` errors on the SDK surface, pin the version in
12	// package.json (or adjust the two SDK calls below) and re-run. Everything it
13	// imports from `@/shared/lib/api/mcp` is already unit-tested.
14	import { createServer, type IncomingMessage, type ServerResponse } from 'node:http';
15	import { McpServer } from '@modelcontextprotocol/sdk/server/mcp.js';
16	import { StreamableHTTPServerTransport } from '@modelcontextprotocol/sdk/server/streamableHttp.js';
17	import { createClient } from '@supabase/supabase-js';
18	import {
19	  generateClerkProtectedResourceMetadata,
20	  corsHeaders,
21	} from '@clerk/mcp-tools/server';
22	import { z } from 'zod';
23	import {
24	  listTools,
25	  dispatchTool,
26	  McpToolError,
27	  createApiKeyAuthResolver,
28	  createOAuthAuthResolver,
29	  createCompositeAuthResolver,
30	  supabaseApiKeyLookup,
31	  supabaseAuditSink,
32	  RateLimiter,
33	  DEFAULT_MAX_PAYLOAD_BYTES,
34	  type McpAuthContext,
35	} from '@/shared/lib/api/mcp';
36	import { makeClerkVerifier } from './clerkAuth';
37	
38	const VERSION = '0.1.0';
39	const {
40	  SUPABASE_URL,
41	  SUPABASE_ANON_KEY,
42	  SUPABASE_JWT_SECRET,
43	  CLERK_SECRET_KEY,
44	  CLERK_PUBLISHABLE_KEY,
45	  MCP_PUBLIC_URL = 'https://mcp.canvasm.app',
46	  PORT = '8787',
47	} = process.env;
48	
49	if (
50	  !SUPABASE_URL ||
51	  !SUPABASE_ANON_KEY ||
52	  !SUPABASE_JWT_SECRET ||
53	  !CLERK_SECRET_KEY ||
54	  !CLERK_PUBLISHABLE_KEY
55	) {
56	  console.error(
57	    'Missing env. Required: SUPABASE_URL, SUPABASE_ANON_KEY, SUPABASE_JWT_SECRET, CLERK_SECRET_KEY, CLERK_PUBLISHABLE_KEY.'
58	  );
59	  process.exit(1);
60	}
61	
62	// The OAuth resource id this server represents (must match what clients request).
63	const RESOURCE_URL = `${MCP_PUBLIC_URL}/mcp`;
64	// RFC 9728 Protected Resource Metadata path (also served with a `/mcp` suffix).
65	const PRM_PATH = '/.well-known/oauth-protected-resource';
66	
67	// One anon client for key lookups; the resolver mints a per-user JWT + client.
68	const anon = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);
69	// Two auth paths behind one endpoint: `mk_live_…` personal API keys (CLI) and
70	// Clerk OAuth access tokens (claude.ai / Desktop connectors). Both resolve to
71	// the same RLS-scoped McpAuthContext.
72	const resolveApiKey = createApiKeyAuthResolver({
73	  jwtSecret: SUPABASE_JWT_SECRET,
74	  supabaseUrl: SUPABASE_URL,
75	  anonKey: SUPABASE_ANON_KEY,
76	  lookupKey: supabaseApiKeyLookup(anon),
77	});
78	const resolveOAuth = createOAuthAuthResolver({
79	  jwtSecret: SUPABASE_JWT_SECRET,
80	  supabaseUrl: SUPABASE_URL,
81	  anonKey: SUPABASE_ANON_KEY,
82	  verifyOAuthToken: makeClerkVerifier({
83	    secretKey: CLERK_SECRET_KEY,
84	    publishableKey: CLERK_PUBLISHABLE_KEY,
85	    resourceUrl: RESOURCE_URL,
86	    authorizedParties: ['https://claude.ai', 'https://claude.com'],
87	  }),
88	});
89	const resolveAuth = createCompositeAuthResolver({
90	  apiKey: resolveApiKey,
91	  oauth: resolveOAuth,
92	});
93	
94	// 120 calls burst, 2/s sustained, per user (in-memory — see README for scaling).
95	const rateLimiter = new RateLimiter(120, 2);
96	
97	function headersOf(req: IncomingMessage): Record<string, string | undefined> {
98	  const out: Record<string, string | undefined> = {};
99	  for (const [k, v] of Object.entries(req.headers)) {
100	    out[k.toLowerCase()] = Array.isArray(v) ? v.join(',') : v;
101	  }
102	  return out;
103	}
104	
105	function readJson(req: IncomingMessage): Promise<unknown> {
106	  return new Promise((resolve, reject) => {
107	    let data = '';
108	    req.on('data', (c) => (data += c));
109	    req.on('end', () => {
